import React, { isValidElement, useMemo } from 'react';
import PropTypes from 'prop-types';
import classNames from 'classnames';
import Tippy from '@andes-tippy-js/react/headless';
import warning from '@andes/common/build/utils/warning';
import usePreventClickOutside from '../hooks/usePreventFocusClickOutside';
import { namespace } from '../constants';
import { BOTTOM, PLACEMENTS } from '../constants/layout';
import { ALLOWED_PADDING_SIZES } from '../constants/paddings';
import { WARNING_FLIP_MODIFIER } from '../constants/warnings';
import { useAndesContext } from '@andes/context';

/** @typedef {import('../..').PopperProps} PopperPublicProps */

/**
 * @typedef {Object} PopperInternalProps
 * @prop {{ root?: Record<string, string>, content?: Record<string, string> }} [attrs]
 * @prop {{ root?: string, content?: string }} [classNames]
 */

/** @type {import('react').FunctionComponent<PopperInternalProps & PopperPublicProps>} */
const Popper = ({
  attrs = {},
  appendTo,
  children,
  className,
  classNames: classes = {},
  content,
  focusScope = false,
  id,
  interactive = false,
  interactiveDebounce = 0,
  onClickOutside,
  onHidden,
  onMount,
  paddingSize = 0,
  placement = BOTTOM,
  popperOptions,
  style,
  trigger = 'click focus',
  visible,
  zIndex = 9999,
  ...props
}) => {
  const computedPopperClassName = className || classes?.root;
  const popperClassName = classNames(namespace, computedPopperClassName, [
    `${namespace}--padding-${paddingSize}`,
  ]);
  const popperContentClassName = classNames(
    `${namespace}__content`,
    classes?.content,
  );
  const { device } = useAndesContext();

  const { handleClickOutside, handleHiddenTippy, handleOnMountTippy } = usePreventClickOutside({
    onClickOutside,
    onHidden,
    onMount,
    focusScope,
    device,
  });

  const mergedPopperOptions = useMemo(() => {
    if (!popperOptions) {
      return {
        modifiers: [
          {
            name: 'flip',
            enabled: false,
          },
        ],
      };
    }

    const userModifiers = popperOptions.modifiers || [];

    const userFlipModifier = userModifiers.find(
      (modifier) => modifier.name === 'flip',
    );
    if (userFlipModifier && userFlipModifier.enabled === true) {
      warning(false, WARNING_FLIP_MODIFIER);
    }

    const filteredUserModifiers = userModifiers.filter(
      (modifier) => modifier.name !== 'flip',
    );

    return {
      ...popperOptions,
      modifiers: [
        {
          name: 'flip',
          enabled: false,
        },
        ...filteredUserModifiers,
      ],
    };
  }, [popperOptions]);

  return (
    <Tippy
      render={(_1, _2, instance) => (
        <div
          id={id}
          style={style}
          className={popperClassName}
          data-testid="popper"
          data-andes-popper
          data-andes-popper-outside-root={
            typeof appendTo === 'function' || !interactive || undefined
          }
          {...attrs?.root}
        >
          <div className={popperContentClassName} {...attrs?.content}>
            {isValidElement(content)
              ? React.cloneElement(content, {
                // @ts-expect-error: Themes integration. Check typing.
                instance,
              })
              : content}
          </div>
        </div>
      )}
      appendTo={appendTo}
      placement={placement}
      trigger={visible === undefined ? trigger : undefined}
      visible={visible}
      interactive={interactive}
      interactiveDebounce={interactiveDebounce}
      popperOptions={mergedPopperOptions}
      // @ts-expect-error: Tippy uses a Generic Event
      onClickOutside={handleClickOutside}
      zIndex={zIndex}
      onHidden={handleHiddenTippy}
      onMount={handleOnMountTippy}
      {...props}
    >
      {children}
    </Tippy>
  );
};

Popper.propTypes = {
  attrs: PropTypes.shape({}),
  appendTo: PropTypes.func,
  children: PropTypes.element,
  className: PropTypes.string,
  classNames: PropTypes.shape({}),
  content: PropTypes.node.isRequired,
  focusScope: PropTypes.bool,
  id: PropTypes.string,
  interactive: PropTypes.bool,
  interactiveDebounce: PropTypes.number,
  onClickOutside: PropTypes.func,
  onCreate: PropTypes.func,
  onDestroy: PropTypes.func,
  onHidden: PropTypes.func,
  onHide: PropTypes.func,
  onMount: PropTypes.func,
  onShow: PropTypes.func,
  paddingSize: PropTypes.oneOf(ALLOWED_PADDING_SIZES),
  placement: PropTypes.oneOf(PLACEMENTS),
  popperOptions: PropTypes.shape({}),
  role: PropTypes.string,
  style: PropTypes.shape({}),
  trigger: PropTypes.string,
  visible: PropTypes.bool,
  zIndex: PropTypes.number,
};

export default Popper;
