import React, { useCallback, useRef, useState } from 'react';

/**
 * @param {HTMLElement} parent
 * @param {HTMLElement} child
 * @returns
 */
const actualContains = (parent, child) => {
  let target = child;

  while (target) {
    if (parent.contains(target)) {
      return true;
    }
    // @ts-expect-error
    target = (target.getRootNode?.())?.host;
  }
  return false;
};

const EVENT_OPTIONS = { passive: false, capture: true };

/**
 * @typedef {Object} usePreventFocusClickOutsideProps
 * @prop {import('../..').PopperProps['focusScope']} focusScope
 * @prop {import('@andes/context').Device} [device]
 * @prop {import('../..').PopperProps['onClickOutside']} [onClickOutside]
 * @prop {import('../..').PopperProps['onHidden']} [onHidden]
 * @prop {import('../..').PopperProps['onMount']} [onMount]
 */

/** @param {usePreventFocusClickOutsideProps} usePreventFocusClickOutside */
const usePreventFocusClickOutside = ({ onClickOutside, onHidden, onMount, focusScope, device }) => {
  const [preventFocus, setPreventFocus] = useState(/** @type {boolean | undefined} */ (undefined));
  const wasTouchedOutside = useRef(false);

  const handleTouchEnd = useCallback((/** @type {Event} */ event) => {
    if (wasTouchedOutside.current) {
      wasTouchedOutside.current = false;
      event.preventDefault();
      if (typeof onClickOutside === 'function') {
        onClickOutside(
          null,
          /** @type {React.MouseEvent} */ (/** @type {unknown} */ (event)),
        );
      }
    }
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  /**
   * @param {import('tippy.js').Instance} instance
   * @param {React.MouseEvent} event
   */
  const handleClickOutside = (instance, event) => {
    if (device?.osName !== 'android') {
      const x = event.clientX;
      const y = event.clientY;

      if (typeof x === 'number' || typeof y === 'number') {
        const realTarget = /** @type {HTMLElement} */ (document.elementFromPoint(x, y));

        if (realTarget && actualContains(instance.popper, realTarget)) return;
      }
    }

    if (focusScope) {
      const isMouseEvent = event instanceof MouseEvent;

      if (isMouseEvent) {
        event.preventDefault();
      } else {
        wasTouchedOutside.current = true;
      }

      setPreventFocus(true);

      // @ts-expect-error: focusScope environment allows blur
      if (instance?.reference) instance.reference.blur();

      if (isMouseEvent && typeof onClickOutside === 'function') onClickOutside(instance, event);
    } else if (typeof onClickOutside === 'function') onClickOutside(instance, event);
  };

  /** @param {import('tippy.js').Instance} instance */
  const handleHiddenTippy = (instance) => {
    if (typeof onHidden === 'function') onHidden(instance, { preventFocus });

    if (focusScope) {
      document.removeEventListener('touchend', handleTouchEnd, EVENT_OPTIONS);
    }

    setPreventFocus(false);
  };

  /** @param {import('tippy.js').Instance} instance */
  const handleOnMountTippy = (instance) => {
    if (focusScope) {
      document.addEventListener('touchend', handleTouchEnd, EVENT_OPTIONS);
    }

    if (typeof onMount === 'function') onMount(instance);
  };

  return { handleClickOutside, handleHiddenTippy, handleOnMountTippy };
};

export default usePreventFocusClickOutside;
